'use client';

import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import * as z from "zod";
import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { notFound, useParams, useRouter } from "next/navigation";
import { mockProjects } from "@/lib/mock-data";
import type { ProjectStatus } from "@/lib/types";
import { ArrowLeft } from "lucide-react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";

const formSchema = z.object({
  title: z.string().min(5, "El título debe tener al menos 5 caracteres."),
  abstract: z.string().min(20, "El resumen debe tener al menos 20 caracteres."),
  category: z.string().min(1, "La categoría es obligatoria."),
  timeline: z.string().min(1, "La duración es obligatoria."),
  studentLimit: z.coerce.number().min(1, "Debe haber al menos un estudiante."),
  requiredSkills: z.string().min(1, "Se requiere al menos una habilidad."),
  status: z.enum([
    "Draft",
    "Pending Approval",
    "Approved",
    "Rejected with feedback",
    "In Development",
    "Finished",
  ]),
});

export default function EditProjectPage() {
    const { toast } = useToast();
    const router = useRouter();
    const params = useParams();
    const projectId = params.id as string;
    const project = mockProjects.find((p) => p.id === projectId);

    if (!project) {
        notFound();
    }

    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            ...project,
            requiredSkills: project.requiredSkills.join(', '),
        },
    });

    function onSubmit(values: z.infer<typeof formSchema>) {
        console.log({ ...values, requiredSkills: values.requiredSkills.split(',').map(s => s.trim()) });
        toast({
            title: "Proyecto actualizado",
            description: "Los detalles del proyecto han sido actualizados con éxito.",
        });
        router.push(`/projects/${projectId}`);
    }

    return (
         <div className="space-y-6">
             <div className="flex items-center gap-4">
                <Link href={`/projects/${projectId}`}>
                    <Button variant="outline" size="icon">
                        <ArrowLeft className="h-4 w-4" />
                    </Button>
                </Link>
                <div>
                    <h1 className="text-3xl font-bold font-headline">Editar Proyecto</h1>
                    <p className="text-muted-foreground">Modifica los detalles de &quot;{project.title}&quot;.</p>
                </div>
            </div>
            <Card>
                <CardContent className="pt-6">
                    <Form {...form}>
                        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
                            <FormField
                                control={form.control}
                                name="title"
                                render={({ field }) => (
                                    <FormItem>
                                    <FormLabel>Título del proyecto</FormLabel>
                                    <FormControl>
                                        <Input placeholder="Ej: Plataforma IA para agricultura" {...field} />
                                    </FormControl>
                                    <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="abstract"
                                render={({ field }) => (
                                    <FormItem>
                                    <FormLabel>Resumen del proyecto</FormLabel>
                                    <FormControl>
                                        <Textarea placeholder="Describe brevemente tu proyecto..." className="min-h-[150px]" {...field} />
                                    </FormControl>
                                    <FormMessage />
                                    </FormItem>
                                )}
                            />
                             <div className="grid md:grid-cols-2 gap-8">
                                <FormField
                                    control={form.control}
                                    name="category"
                                    render={({ field }) => (
                                        <FormItem>
                                        <FormLabel>Categoría</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej: Tecnología" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="timeline"
                                    render={({ field }) => (
                                        <FormItem>
                                        <FormLabel>Duración estimada</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej: 6 meses" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                        </FormItem>
                                    )}
                                />
                             </div>
                             <div className="grid md:grid-cols-2 gap-8">
                                <FormField
                                    control={form.control}
                                    name="studentLimit"
                                    render={({ field }) => (
                                        <FormItem>
                                        <FormLabel>Límite de estudiantes</FormLabel>
                                        <FormControl>
                                            <Input type="number" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="requiredSkills"
                                    render={({ field }) => (
                                        <FormItem>
                                        <FormLabel>Habilidades requeridas</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej: React, Python, UI/UX" {...field} />
                                        </FormControl>
                                        <FormDescription>
                                            Separa las habilidades por comas.
                                        </FormDescription>
                                        <FormMessage />
                                        </FormItem>
                                    )}
                                />
                             </div>
                              <FormField
                                control={form.control}
                                name="status"
                                render={({ field }) => (
                                  <FormItem>
                                    <FormLabel>Estado del proyecto</FormLabel>
                                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                                      <FormControl>
                                        <SelectTrigger>
                                          <SelectValue placeholder="Selecciona un estado" />
                                        </SelectTrigger>
                                      </FormControl>
                                      <SelectContent>
                                        {(Object.keys(form.getValues("status")) as ProjectStatus[]).map((status) => (
                                            <SelectItem key={status} value={status}>{status}</SelectItem>
                                        ))}
                                      </SelectContent>
                                    </Select>
                                    <FormMessage />
                                  </FormItem>
                                )}
                              />
                            <div className="flex justify-end gap-2">
                                <Link href={`/projects/${projectId}`}>
                                    <Button type="button" variant="ghost">Cancelar</Button>
                                </Link>
                                <Button type="submit">Guardar cambios</Button>
                            </div>
                        </form>
                    </Form>
                </CardContent>
            </Card>

        </div>
    )
}
